  2→ * Files API Client
  3→ *
  4→ * TypeScript client for File API with fetch wrapper.
  5→ * Provides typed methods for file upload, retrieval, and deletion.
  6→ */
  7→
  8→import type { ApiResponse, ApiClientConfig } from './types';
  9→import { ApiClientError, parseApiError, parseJson } from './shared';
 10→
 11→export { ApiClientError } from './shared';
 12→
 13→/**
 14→ * Default base URL for API requests
 15→ */
 16→const DEFAULT_BASE_URL = '/api';
 17→
 18→/**
 19→ * File entity data (mirrors Prisma FileEntity model)
 20→ */
 21→export interface FileEntityData {
 22→  id: string;
 23→  fileName: string;
 24→  storageKey: string;
 25→  mimeType: string | null;
 26→  size: number;
 27→  bucket: string;
 28→  uploadedBy: string | null;
 29→  createdAt: Date;
 30→}
 31→
 32→/**
 33→ * File upload response
 34→ */
 35→export interface FileUploadResponse {
 36→  file: FileEntityData;
 37→  downloadUrl?: string;
 38→  expiresIn?: number;
 39→}
 40→
 41→/**
 42→ * File upload options
 43→ */
 44→export interface FileUploadOptions {
 45→  file: File;
 46→  entityType?: string;
 47→  entityId?: string;
 48→  uploadedBy?: string;
 49→  onProgress?: (progress: number) => void;
 50→}
 51→
 52→/**
 53→ * Files API Client
 54→ */
 55→export class FilesApiClient {
 56→  private baseUrl: string;
 57→  private fetchFn: typeof globalThis.fetch;
 58→  private defaultHeaders: Record<string, string>;
 59→
 60→  constructor(config: ApiClientConfig = {}) {
 61→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 62→    this.fetchFn = config.fetch ?? fetch;
 63→    this.defaultHeaders = {
 64→      ...config.headers,
 65→    };
 66→  }
 67→
 68→  /**
 69→   * Build full URL for endpoint
 70→   */
 71→  private url(path: string, params?: Record<string, string | undefined>): string {
 72→    const fullUrl = `${this.baseUrl}${path}`;
 73→
 74→    if (params) {
 75→      const searchParams = new URLSearchParams();
 76→      for (const [key, value] of Object.entries(params)) {
 77→        if (value !== undefined) {
 78→          searchParams.append(key, value);
 79→        }
 80→      }
 81→      const queryString = searchParams.toString();
 82→      if (queryString) {
 83→        return `${fullUrl}?${queryString}`;
 84→      }
 85→    }
 86→
 87→    return fullUrl;
 88→  }
 89→
 90→  /**
 91→   * POST /api/files
 92→   *
 93→   * Upload a file via multipart form data.
 94→   */
 95→  async uploadFile(options: FileUploadOptions): Promise<ApiResponse<FileEntityData>> {
 96→    const { file, entityType = 'general', entityId = 'temp', uploadedBy, onProgress } = options;
 97→
 98→    const formData = new FormData();
 99→    formData.append('file', file);
100→    formData.append('entityType', entityType);
101→    formData.append('entityId', entityId);
102→    if (uploadedBy) {
103→      formData.append('uploadedBy', uploadedBy);
104→    }
105→
106→    // Use XMLHttpRequest for progress tracking if needed
107→    if (onProgress && typeof XMLHttpRequest !== 'undefined') {
108→      return new Promise((resolve, reject) => {
109→        const xhr = new XMLHttpRequest();
110→
111→        xhr.upload.addEventListener('progress', (e) => {
112→          if (e.lengthComputable) {
113→            onProgress(Math.round((e.loaded / e.total) * 100));
114→          }
115→        });
116→
117→        xhr.addEventListener('load', () => {
118→          if (xhr.status >= 200 && xhr.status < 300) {
119→            try {
120→              const data = JSON.parse(xhr.responseText);
121→              resolve(data);
122→            } catch (err) {
123→              reject(new ApiClientError(xhr.status, 'Invalid response', 'Failed to parse JSON response'));
124→            }
125→          } else {
126→            try {
127→              const error = JSON.parse(xhr.responseText);
128→              reject(new ApiClientError(xhr.status, error.error || 'Upload failed', error.message || 'Unknown error'));
129→            } catch {
130→              reject(new ApiClientError(xhr.status, 'Upload failed', xhr.statusText));
131→            }
132→          }
133→        });
134→
135→        xhr.addEventListener('error', () => {
136→          reject(new ApiClientError(0, 'Network error', 'Failed to upload file'));
137→        });
138→
139→        xhr.open('POST', this.url('/files'));
140→        for (const [key, value] of Object.entries(this.defaultHeaders)) {
141→          if (key.toLowerCase() !== 'content-type') {
142→            xhr.setRequestHeader(key, value);
143→          }
144→        }
145→        xhr.send(formData);
146→      });
147→    }
148→
149→    // Fallback to fetch if no progress tracking needed
150→    const response = await this.fetchFn(this.url('/files'), {
151→      method: 'POST',
152→      headers: this.defaultHeaders,
153→      body: formData,
154→    });
155→
156→    if (!response.ok) {
157→      return parseApiError(response);
158→    }
159→
160→    return parseJson<ApiResponse<FileEntityData>>(response);
161→  }
162→
163→  /**
164→   * GET /api/files/[id]
165→   *
166→   * Fetch file metadata and generate presigned download URL.
167→   */
168→  async getFile(id: string, expiresIn?: number): Promise<ApiResponse<FileUploadResponse>> {
169→    if (!id) {
170→      throw new ApiClientError(400, 'Validation failed', 'id is required');
171→    }
172→
173→    const response = await this.fetchFn(
174→      this.url(`/files/${id}`, { expiresIn: expiresIn?.toString() }),
175→      {
176→        headers: this.defaultHeaders,
177→      }
178→    );
179→
180→    if (!response.ok) {
181→      return parseApiError(response);
182→    }
183→
184→    return parseJson<ApiResponse<FileUploadResponse>>(response);
185→  }
186→
187→  /**
188→   * DELETE /api/files/[id]
189→   *
190→   * Soft-delete a file by setting deletedAt timestamp.
191→   */
192→  async deleteFile(id: string, removeFromStorage = false): Promise<ApiResponse<FileEntityData>> {
193→    if (!id) {
194→      throw new ApiClientError(400, 'Validation failed', 'id is required');
195→    }
196→
197→    const response = await this.fetchFn(
198→      this.url(`/files/${id}`, { removeFromStorage: removeFromStorage ? 'true' : undefined }),
199→      {
200→        method: 'DELETE',
201→        headers: this.defaultHeaders,
202→      }
203→    );
204→
205→    if (!response.ok) {
206→      return parseApiError(response);
207→    }
208→
209→    return parseJson<ApiResponse<FileEntityData>>(response);
210→  }
211→}
